mapper.insert:
insert into alert_rule (
    product_key, product_name, module_id, module_name, function_name, function_id, iot_id, device_name,
    alert_data_type, alert_rule_name, operator, `value`, duration, alert_effective_period, alert_silent_period,
    status, create_time, update_time, create_by, update_by, remark
) values (
    #{productKey}, #{productName}, #{moduleId}, #{moduleName}, #{functionName}, #{functionId}, #{iotId}, #{deviceName},
    #{alertDataType}, #{alertRuleName}, #{operator}, #{value}, #{duration}, #{alertEffectivePeriod}, #{alertSilentPeriod},
    #{status}, now(), now(), #{createBy}, #{updateBy}, #{remark}
)

mapper.update:
update alert_rule
product_key = #{productKey}, product_name = #{productName}, module_id = #{moduleId}, module_name = #{moduleName}, function_name = #{functionName}, function_id = #{functionId}, iot_id = #{iotId}, device_name = #{deviceName}, alert_data_type = #{alertDataType}, alert_rule_name = #{alertRuleName}, operator = #{operator}, `value` = #{value}, duration = #{duration}, alert_effective_period = #{alertEffectivePeriod}, alert_silent_period = #{alertSilentPeriod}, status = #{status}, update_by = #{updateBy}, remark = #{remark}, update_time = now()
where id = #{id}

mapper.select:
select *
from alert_rule

    
        and product_key = #{dto.productKey}
    
    
        and alert_rule_name like concat('%', #{dto.alertRuleName}, '%')
    
    
        and status = #{dto.status}
    

order by create_time desc
